export enum Category {
  GROWTH = 'Success & Growth Mindset',
  FOCUS = 'Focus & Clarity',
  WISDOM = 'Wisdom & Intelligence',
  RESILIENCE = 'Resilience & Transformation',
  ACTION = 'Empowerment & Action',
  EMOTION = 'Emotional Intelligence',
  PHILOSOPHY = 'Life Philosophy & Energy',
  MODERN = 'Modern Wisdom',
}

export interface WisdomNodeData {
  id: string;
  category: Category;
  title: string;
  insight: string; // The deeper text shown in modal
  position: [number, number, number]; // x, y, z coordinates
  color: string;
}

export interface BrainState {
  isHovered: boolean;
  selectedNode: WisdomNodeData | null;
  rotationSpeed: number;
}

import { Category, WisdomNodeData } from './types';
import * as THREE from 'three';

// Helper to distribute points on a sphere roughly
const getSpherePosition = (radius: number, phi: number, theta: number): [number, number, number] => {
  const x = radius * Math.sin(phi) * Math.cos(theta);
  const y = radius * Math.cos(phi);
  const z = radius * Math.sin(phi) * Math.sin(theta);
  return [x, y, z];
};

