export const WISDOM_NODES: WisdomNodeData[] = rawNodes.map((node, index) => {
  // Distribute mostly evenly around a sphere radius 1.8 to 2.2
  const phi = Math.acos(-1 + (2 * index) / rawNodes.length);
  const theta = Math.sqrt(rawNodes.length * Math.PI) * phi;

  // Add some jitter for organic feel
  const r = 2.0 + (Math.random() * 0.4); 

  return {
    id: `node-${index}`,
    category: node.cat,
    title: node.title,
    insight: node.insight,
    position: getSpherePosition(r, phi, theta),
    color: COLORS[node.cat],
  };
});

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { MeshDistortMaterial, Sphere } from '@react-three/drei';
import * as THREE from 'three';

interface BrainMeshProps {
  isHovered: boolean;
}

export const BrainMesh: React.FC<BrainMeshProps> = ({ isHovered }) => {
  const leftHemiRef = useRef<THREE.Mesh>(null);
  const rightHemiRef = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    const time = state.clock.getElapsedTime();

    // Subtle breathing animation
    if (leftHemiRef.current) {
      leftHemiRef.current.scale.setScalar(1 + Math.sin(time * 0.5) * 0.02);
    }
    if (rightHemiRef.current) {
      rightHemiRef.current.scale.setScalar(1 + Math.sin(time * 0.5 + 1) * 0.02);
    }
  });

  const materialProps = {
    color: isHovered ? "#a5b4fc" : "#e0e7ff",
    wireframe: true,
    transparent: true,
    opacity: 0.6,
    roughness: 0.2,
    metalness: 0.1,
    distort: 0.4,
    speed: 2,
  };

  return (
    <group>
      {/* Left Hemisphere */}
      <Sphere ref={leftHemiRef} args={[1.2, 64, 64]} position={[-0.7, 0, 0]}>
        <MeshDistortMaterial {...materialProps} />
      </Sphere>

      {/* Right Hemisphere */}
      <Sphere ref={rightHemiRef} args={[1.2, 64, 64]} position={[0.7, 0, 0]}>
        <MeshDistortMaterial {...materialProps} />
      </Sphere>

      {/* Internal Glow Core */}
      <pointLight position={[0, 0, 0]} intensity={1.5} color="#818cf8" distance={5} />
    </group>
  );
};

import React, { useRef, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import { Html } from '@react-three/drei';
import * as THREE from 'three';
import { WisdomNodeData } from '../types';

interface WisdomNodeProps {
  data: WisdomNodeData;
  onSelect: (node: WisdomNodeData) => void;
}

export const WisdomNode: React.FC<WisdomNodeProps> = ({ data, onSelect }) => {
  const meshRef = useRef<THREE.Group>(null);
  const [hovered, setHovered] = useState(false);
  const randomPhase = useRef(Math.random() * Math.PI * 2);

  useFrame((state) => {
    if (meshRef.current) {
      const t = state.clock.getElapsedTime() + randomPhase.current;
      // Floating animation
      meshRef.current.position.y = data.position[1] + Math.sin(t * 1.5) * 0.1;

      // Look at camera
      meshRef.current.lookAt(state.camera.position);
    }
  });

  return (
    <group 
      position={new THREE.Vector3(...data.position)} 
      ref={meshRef}
    >
      {/* Connection Line to center (approximate) */}
      <mesh position={[0, 0, -1]} rotation={[Math.PI / 2, 0, 0]}>
        <cylinderGeometry args={[0.005, 0.005, 2, 4]} />
        <meshBasicMaterial color={data.color} transparent opacity={0.3} />
      </mesh>

      {/* Interactive Trigger Area */}
      <mesh 
        onClick={() => onSelect(data)}
        onPointerOver={() => { document.body.style.cursor = 'pointer'; setHovered(true); }}
        onPointerOut={() => { document.body.style.cursor = 'auto'; setHovered(false); }}
      >
        <sphereGeometry args={[0.15, 16, 16]} />
        <meshStandardMaterial 
          color={hovered ? '#ffffff' : data.color} 
          emissive={data.color}
          emissiveIntensity={hovered ? 2 : 0.5}
        />
      </mesh>

      {/* Floating Label */}
      <Html
        position={[0.2, 0, 0]}
        center
        distanceFactor={10}
        style={{
          pointerEvents: 'none',
          opacity: hovered ? 1 : 0.7,
          transition: 'all 0.3s ease',
          transform: hovered ? 'scale(1.1)' : 'scale(1)',
        }}
      >
        <div className={`
          backdrop-blur-sm bg-black/40 border border-white/10 
          px-3 py-1.5 rounded-full whitespace-nowrap
          flex items-center gap-2 select-none
        `}>
          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: data.color }} />
          <span className="text-white text-sm font-doodle tracking-wide shadow-black drop-shadow-md">
            {data.title}
          </span>
        </div>
      </Html>
    </group>
  );
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import { Points, PointMaterial } from '@react-three/drei';
import * as THREE from 'three';

export const Particles: React.FC = () => {
  const ref = useRef<THREE.Points>(null);

  // Generate random points
  const [positions] = React.useState(() => {
    const pos = new Float32Array(1000 * 3);
    for (let i = 0; i < 1000; i++) {
      const r = 4 + Math.random() * 6;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.acos(2 * Math.random() - 1);

      pos[i * 3] = r * Math.sin(phi) * Math.cos(theta);
      pos[i * 3 + 1] = r * Math.cos(phi);
      pos[i * 3 + 2] = r * Math.sin(phi) * Math.sin(theta);
    }
    return pos;
  });

  useFrame((state, delta) => {
    if (ref.current) {
      ref.current.rotation.y += delta * 0.05;
      ref.current.rotation.x += delta * 0.02;
    }
  });

  return (
    <group rotation={[0, 0, Math.PI / 4]}>
      <Points ref={ref} positions={positions} stride={3} frustumCulled={false}>
        <PointMaterial
          transparent
          color="#8b5cf6"
          size={0.03}
          sizeAttenuation={true}
          depthWrite={false}
          opacity={0.6}
        />
      </Points>
    </group>
  );
};

