import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';

const MatrixShaderMaterial = {
  uniforms: {
    uTime: { value: 0 },
    uColor: { value: new THREE.Color('#00FF41') },
    uResolution: { value: new THREE.Vector2(1, 1) },
  },
  vertexShader: `
    varying vec2 vUv;
    void main() {
      vUv = uv;
      gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
    }
  `,
  fragmentShader: `
    uniform float uTime;
    uniform vec3 uColor;
    varying vec2 vUv;

    float random(vec2 st) {
        return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
    }

    void main() {
        vec2 uv = vUv;

        // Matrix rain column logic
        float columns = 50.0;
        float x = floor(uv.x * columns);
        float y = floor(uv.y * columns); // Pixelate vertical

        // Falling speed varies per column
        float speed = 2.0 + random(vec2(x, 1.0)) * 5.0;
        float yOffset = uTime * speed;

        // The "character" changing logic
        float charChange = uTime * 10.0;
        float charVal = random(vec2(x, floor((uv.y + yOffset) * 20.0)));

        // Trail effect
        float trail = fract(uv.y * 20.0 + yOffset);
        float glow = 1.0 - trail;
        glow = pow(glow, 5.0); // Make it sharp

        // Random flickering brightness
        float flicker = random(vec2(x, y + floor(uTime * 10.0))) > 0.9 ? 1.0 : 0.5;

        // Combine
        vec3 finalColor = uColor * glow * flicker;

        // Mask some columns to have gaps
        if(random(vec2(x, 0.0)) > 0.8) finalColor *= 0.0;

        // Fade out at bottom/top
        finalColor *= smoothstep(0.0, 0.2, uv.y) * smoothstep(1.0, 0.8, uv.y);

        gl_FragColor = vec4(finalColor, 0.3 * glow); // Transparency
    }
  `
};

export const MatrixBackground: React.FC = () => {
  const meshRef = useRef<THREE.Mesh>(null);
  const shaderRef = useRef<THREE.ShaderMaterial>(null);

  useFrame((state) => {
    if (shaderRef.current) {
      shaderRef.current.uniforms.uTime.value = state.clock.getElapsedTime();
    }
  });

  return (
    <mesh ref={meshRef} position={[0, 0, -10]} scale={[40, 40, 1]}>
      <planeGeometry args={[1, 1]} />
      <shaderMaterial
        ref={shaderRef}
        args={[MatrixShaderMaterial]}
        transparent
        depthWrite={false}
      />
    </mesh>
  );
};

import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Text } from '@react-three/drei';
import * as THREE from 'three';
import { WordData } from '../types';
import { FONT_URL } from '../constants';

interface WordNodeProps {
  data: WordData;
  onSelect: (node: WordData) => void;
  hoveringGlobal: boolean;
}

export const WordNode: React.FC<WordNodeProps> = ({ data, onSelect, hoveringGlobal }) => {
  const textRef = useRef<THREE.Mesh>(null);
  const [hovered, setHovered] = useState(false);
  const originalPos = useRef(new THREE.Vector3(...data.position));

  // Random slight drift offset
  const driftPhase = useRef(Math.random() * Math.PI * 2);
  const blinkRate = useRef(Math.random() * 0.5 + 0.1);

  useFrame((state) => {
    if (textRef.current) {
      const t = state.clock.getElapsedTime();

      // Look at camera for readability? No, look away from center to form shape
      textRef.current.lookAt(0, 0, 0); 
      // Flip so text is readable from outside
      textRef.current.rotateY(Math.PI); 

      // Gentle drift breathing
      const drift = Math.sin(t + driftPhase.current) * 0.05;
      textRef.current.position.copy(originalPos.current).addScalar(drift);

      // Glitch effect on hover
      if (hovered) {
        textRef.current.position.x += (Math.random() - 0.5) * 0.05;
      }
    }
  });

  const baseColor = data.isHighlight ? '#00FFAA' : '#00FF41';
  const activeColor = '#BFFF00';

  return (
    <group>
      <Text
        ref={textRef as any}
        position={data.position}
        font={FONT_URL}
        fontSize={hovered ? 0.25 : 0.18}
        color={hovered ? activeColor : baseColor}
        anchorX="center"
        anchorY="middle"
        characters="ABCDEFGHIJKLMNOPQRSTUVWXYZ_"
        onClick={(e) => {
            e.stopPropagation();
            onSelect(data);
        }}
        onPointerOver={(e) => {
            e.stopPropagation();
            document.body.style.cursor = 'crosshair';
            setHovered(true);
        }}
        onPointerOut={(e) => {
            document.body.style.cursor = 'default';
            setHovered(false);
        }}
        fillOpacity={hovered ? 1 : (hoveringGlobal ? 0.3 : 0.85)}
        outlineWidth={hovered ? 0.005 : 0}
        outlineColor={activeColor}
      >
        {data.text}
      </Text>
    </group>
  );
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
