import React, { useRef, useState } from 'react';
import { useFrame } from '@react-three/fiber';
import { Text } from '@react-three/drei';
import * as THREE from 'three';
import { WordData } from '../types';
import { FONT_URL } from '../constants';

interface WordNodeProps {
  data: WordData;
  onSelect: (node: WordData) => void;
  hoveringGlobal: boolean;
}

export const WordNode: React.FC<WordNodeProps> = ({ data, onSelect, hoveringGlobal }) => {
  const textRef = useRef<THREE.Mesh>(null);
  const [hovered, setHovered] = useState(false);
  const originalPos = useRef(new THREE.Vector3(...data.position));

  // Random slight drift offset
  const driftPhase = useRef(Math.random() * Math.PI * 2);

  useFrame((state) => {
    if (textRef.current) {
      const t = state.clock.getElapsedTime();

      // Look away from center to form shape
      textRef.current.lookAt(0, 0, 0); 
      // Flip so text is readable from outside
      textRef.current.rotateY(Math.PI); 

      // Gentle drift breathing
      const drift = Math.sin(t + driftPhase.current) * 0.05;
      textRef.current.position.copy(originalPos.current).addScalar(drift);

      // Glitch effect on hover
      if (hovered) {
        textRef.current.position.x += (Math.random() - 0.5) * 0.05;
      }
    }
  });

  const baseColor = data.isHighlight ? '#00FFAA' : '#00FF41';
  const activeColor = '#BFFF00';

  // Calculate opacity: if any node is hovered, dim others. If this one is hovered, stay bright.
  const opacity = hovered ? 1 : (hoveringGlobal ? 0.2 : 0.85);

  return (
    <group>
      <Text
        ref={textRef as any}
        position={data.position}
        // Removed characters prop to prevent filtering issues
        // Using Roboto Mono to ensure visibility
        font={FONT_URL}
        fontSize={hovered ? 0.35 : 0.25}
        color={hovered ? activeColor : baseColor}
        anchorX="center"
        anchorY="middle"
        onClick={(e) => {
            e.stopPropagation();
            onSelect(data);
        }}
        onPointerOver={(e) => {
            e.stopPropagation();
            document.body.style.cursor = 'crosshair';
            setHovered(true);
        }}
        onPointerOut={(e) => {
            document.body.style.cursor = 'default';
            setHovered(false);
        }}
        fillOpacity={opacity}
        outlineWidth={hovered ? 0.005 : 0}
        outlineColor={activeColor}
      >
        {data.text}
      </Text>
    </group>
  );
};

import React, { useRef } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { WordNode } from './WordNode';
import { BRAIN_WORDS } from '../constants';
