interface TypographyBrainProps {
  isHovered: boolean;
  onNodeSelect: (node: WordData) => void;
}

export const TypographyBrain: React.FC<TypographyBrainProps> = ({ isHovered, onNodeSelect }) => {
  const groupRef = useRef<THREE.Group>(null);
  const currentSpeed = useRef(0.15); // Base speed

  useFrame((state, delta) => {
    if (groupRef.current) {
        // Rotation Logic
        if (isHovered) {
            // Decelerate
            currentSpeed.current = THREE.MathUtils.lerp(currentSpeed.current, 0, delta * 2);
        } else {
            // Accelerate back to normal
            currentSpeed.current = THREE.MathUtils.lerp(currentSpeed.current, 0.1, delta * 1);
        }

        groupRef.current.rotation.y += currentSpeed.current * delta;
    }
  });

  return (
    <group ref={groupRef}>
      {BRAIN_WORDS.map((node) => (
        <WordNode 
            key={node.id} 
            data={node} 
            onSelect={onNodeSelect} 
            hoveringGlobal={isHovered}
        />
      ))}

      {/* Central Neural Glow */}
      <pointLight position={[0,0,0]} intensity={2} color="#00FF41" distance={5} decay={2} />

      {/* Internal Geometry Wireframe (Faint Brain Core) */}
      <mesh scale={[2.8, 2.8, 3.2]}>
         <sphereGeometry args={[1, 16, 16]} />
         <meshBasicMaterial color="#00FF41" wireframe transparent opacity={0.1} />
      </mesh>
    </group>
  );
};

