import { BrainRegion, WordData } from './types';

// Constants for brain geometry
const SCALE = 1.4;

// Helper to generate a position within a volume roughly corresponding to a brain lobe
// We basically model lobes as displaced ellipsoids
const getRegionPosition = (region: BrainRegion, index: number, total: number): [number, number, number] => {
  const side = index % 2 === 0 ? 1 : -1; // Left/Right hemisphere split

  let x = 0, y = 0, z = 0;

  switch (region) {
    case BrainRegion.FRONTAL: // Front
      x = side * (1.2 + Math.random() * 0.8);
      y = 0.5 + Math.random() * 1.5;
      z = 1.5 + Math.random() * 1.5;
      break;
    case BrainRegion.PARIETAL: // Top Back
      x = side * (1.2 + Math.random() * 0.8);
      y = 1.5 + Math.random() * 1.0;
      z = -1.0 + Math.random() * 1.5;
      break;
    case BrainRegion.TEMPORAL: // Sides Low
      x = side * (2.2 + Math.random() * 0.6);
      y = -0.5 + Math.random() * 1.0;
      z = 0.0 + Math.random() * 1.5;
      break;
    case BrainRegion.OCCIPITAL: // Far Back
      x = side * (1.0 + Math.random() * 0.8);
      y = 0.5 + Math.random() * 1.0;
      z = -2.5 + Math.random() * 1.0;
      break;
    case BrainRegion.CEREBELLUM: // Bottom Back
      x = side * (0.8 + Math.random() * 0.5);
      y = -1.5 + Math.random() * 0.8;
      z = -2.0 + Math.random() * 1.0;
      break;
    case BrainRegion.BRAIN_STEM: // Bottom Center
      x = (Math.random() - 0.5) * 0.5;
      y = -2.5 + Math.random() * 1.0;
      z = -0.5 + Math.random() * 0.5;
      break;
    default: // Pathways/General - Scatter internal/around
      x = side * (1.5 + Math.random());
      y = (Math.random() - 0.5) * 3;
      z = (Math.random() - 0.5) * 4;
      break;
  }

  // Apply scale
  return [x * SCALE, y * SCALE, z * SCALE];
};

