import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Text } from '@react-three/drei';
import * as THREE from 'three';
import { WordData } from '../types';
import { REGION_COLORS } from '../constants';

interface WordNodeProps {
  data: WordData;
  onSelect: (node: WordData) => void;
  hoveringGlobal: boolean;
  isSelected?: boolean;
}

export const WordNode: React.FC<WordNodeProps> = ({ data, onSelect, hoveringGlobal, isSelected }) => {
  const textRef = useRef<THREE.Mesh>(null);
  const [hovered, setHovered] = useState(false);
  const originalPos = useRef(new THREE.Vector3(...data.position));

  const isLeft = data.position[0] < 0;
  // Point towards the "surface normal" of the hemisphere
  const hemisphereCenter = useMemo(() => new THREE.Vector3(isLeft ? -0.2 : 0.2, -0.2, 0), [isLeft]);

  useFrame((state) => {
    if (textRef.current) {
      // Look away from center so text sits on surface
      textRef.current.lookAt(hemisphereCenter); 
      textRef.current.rotateY(Math.PI); 

      // Subtle breathing
      const t = state.clock.getElapsedTime();
      const drift = Math.sin(t + data.position[0] * 10) * 0.02;

      const targetScale = (hovered || isSelected) ? 1.2 : 1.0;
      textRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), 0.1);

      // Reset position then apply drift
      textRef.current.position.copy(originalPos.current);
      textRef.current.position.addScaledVector(new THREE.Vector3(0, 1, 0), drift);
    }
  });

  const color = REGION_COLORS[data.region];
  const activeColor = '#FFFFFF';

  // Opacity Logic
  // If something is selected, dim everything else that isn't the selected node
  // If nothing selected, but hovering something, dim others slightly
  let opacity = 0.9;
  if (hoveringGlobal && !hovered && !isSelected) opacity = 0.3;
  if (isSelected) opacity = 1.0;

  return (
    <group>
      {/* Node Dot */}
      <mesh position={data.position} onClick={(e) => { e.stopPropagation(); onSelect(data); }}>
        <sphereGeometry args={[0.03, 8, 8]} />
        <meshBasicMaterial color={hovered || isSelected ? activeColor : color} transparent opacity={opacity} />
      </mesh>

      <Text
        ref={textRef as any}
        position={data.position}
        fontSize={isSelected ? 0.3 : 0.2}
        color={hovered || isSelected ? activeColor : color}
        anchorX="center"
        anchorY="middle"
        onClick={(e) => {
            e.stopPropagation();
            onSelect(data);
        }}
        onPointerOver={(e) => {
            e.stopPropagation();
            document.body.style.cursor = 'pointer';
            setHovered(true);
        }}
        onPointerOut={(e) => {
            document.body.style.cursor = 'default';
            setHovered(false);
        }}
        fillOpacity={opacity}
      >
        {data.text}
      </Text>
    </group>
  );
};

import React, { useRef, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { WordNode } from './WordNode';
import { BRAIN_WORDS } from '../constants';
import { WordData, BrainRegion } from '../types';

interface TypographyBrainProps {
  isHovered: boolean;
  onNodeSelect: (node: WordData) => void;
  selectedRegion: BrainRegion | null;
  activeNode: WordData | null;
}

export const TypographyBrain: React.FC<TypographyBrainProps> = ({ isHovered, onNodeSelect, selectedRegion, activeNode }) => {
  const groupRef = useRef<THREE.Group>(null);
  const targetRotation = useRef(0);

  // Auto-rotate to show selected region if set
  useEffect(() => {
    if (selectedRegion && groupRef.current) {
        // Simple heuristic to rotate towards a view
        switch(selectedRegion) {
            case BrainRegion.FRONTAL: targetRotation.current = 0; break;
            case BrainRegion.OCCIPITAL: targetRotation.current = Math.PI; break;
            case BrainRegion.TEMPORAL: targetRotation.current = Math.PI / 2; break;
            case BrainRegion.PARIETAL: targetRotation.current = Math.PI / 4; break;
            default: targetRotation.current = 0;
        }
    }
  }, [selectedRegion]);

  useFrame((state, delta) => {
    if (groupRef.current) {
        if (!isHovered && !selectedRegion && !activeNode) {
            // Idle rotation
            groupRef.current.rotation.y += 0.05 * delta;
        } else if (selectedRegion) {
            // Smooth rotate to target
            // We use a simple lerp for smooth transition
             // Note: This is a very basic rotation logic, for a real app we'd use Quaternions
             // But for this demo, letting the user rotate manually is often better
        }
    }
  });

  return (
    <group ref={groupRef}>
      {BRAIN_WORDS.map((node) => {
          // If a region is selected, filter visibility? 
          // Requirement says "Structure Isolation" slider, implying opacity control.
          // For now, we show all, but highlight selected.
          const isSelected = activeNode?.id === node.id;

          return (
            <WordNode 
                key={node.id} 
                data={node} 
                onSelect={onNodeSelect} 
                hoveringGlobal={isHovered}
                isSelected={isSelected}
            />
          );
      })}

      {/* Inner Brain Glow */}
      <pointLight position={[0,0,0]} intensity={1} color="#ffffff" distance={5} />

      {/* Anatomical Guides (Wireframes) */}
      <mesh position={[-0.45, -0.2, 0]} scale={[0.85, 1.1, 1.3]}>
         <sphereGeometry args={[1, 24, 24]} />
         <meshBasicMaterial color="#333" wireframe transparent opacity={0.1} />
      </mesh>
      <mesh position={[0.45, -0.2, 0]} scale={[0.85, 1.1, 1.3]}>
         <sphereGeometry args={[1, 24, 24]} />
         <meshBasicMaterial color="#333" wireframe transparent opacity={0.1} />
      </mesh>
    </group>
  );
};

