import React, { useRef, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import * as THREE from 'three';
import { WordNode } from './WordNode';
import { BRAIN_WORDS, REGION_COLORS } from '../constants';
import { WordData } from '../types';

// Helper to get color from region
const getRegionColor = (region: string) => {
    const hex = REGION_COLORS[region as keyof typeof REGION_COLORS] || '#ffffff';
    return new THREE.Color(hex);
};

// Component to render neural connections
const Connectome: React.FC<{ words: WordData[] }> = ({ words }) => {
    const { positions, colors } = useMemo(() => {
        const pos: number[] = [];
        const col: number[] = [];

        // Simple distance-based connection logic
        words.forEach((word, i) => {
            const myPos = new THREE.Vector3(...word.position);

            // Calculate distances to all other nodes
            const distances = words.map((other, idx) => {
                if (i === idx) return { idx, dist: Infinity };
                const otherPos = new THREE.Vector3(...other.position);
                return { idx, dist: myPos.distanceTo(otherPos) };
            });

            // Sort by distance to find nearest neighbors
            distances.sort((a, b) => a.dist - b.dist);

            // Connect to k nearest neighbors to create a network web
            const k = 3;
            const neighbors = distances.slice(0, k);

            neighbors.forEach(n => {
                const neighbor = words[n.idx];

                // Add Connection Line Points
                pos.push(...word.position);
                pos.push(...neighbor.position);

                // Add Gradient Colors (Start -> End)
                const c1 = getRegionColor(word.region);
                const c2 = getRegionColor(neighbor.region);

                col.push(c1.r, c1.g, c1.b);
                col.push(c2.r, c2.g, c2.b);
            });
        });

        return {
            positions: new Float32Array(pos),
            colors: new Float32Array(col)
        };
    }, [words]);

    return (
        <lineSegments>
            <bufferGeometry>
                <bufferAttribute
                    attach="attributes-position"
                    count={positions.length / 3}
                    array={positions}
                    itemSize={3}
                />
                <bufferAttribute
                    attach="attributes-color"
                    count={colors.length / 3}
                    array={colors}
                    itemSize={3}
                />
            </bufferGeometry>
            <lineBasicMaterial 
                vertexColors 
                transparent 
                opacity={0.15} 
                depthWrite={false} 
                blending={THREE.AdditiveBlending}
            />
        </lineSegments>
    );
};

