        const targetSpeed = isHovered ? 0 : 0.05;
        currentSpeed.current = THREE.MathUtils.lerp(currentSpeed.current, targetSpeed, delta * 2);
        groupRef.current.rotation.y += currentSpeed.current * delta;
    }
  });

  return (
    <group ref={groupRef}>
      {/* Neural Pathways */}
