      // Subtle breathing animation
      const t = state.clock.getElapsedTime();
      const drift = Math.sin(t + data.position[0] * 10) * 0.02;

      textRef.current.position.copy(originalPos.current);
      textRef.current.position.addScaledVector(new THREE.Vector3(0, 1, 0), drift);

      // Scale on hover
      const targetScale = hovered ? 1.2 : 1.0;
      textRef.current.scale.lerp(new THREE.Vector3(targetScale, targetScale, targetScale), 0.1);
    }
  });

  const regionColor = REGION_COLORS[data.region] || '#ffffff';
  const activeColor = '#ffffff';

  // Calculate opacity based on interaction state
  const opacity = hovered ? 1 : (hoveringGlobal ? 0.3 : 0.85);

  return (
    <group>
      {/* Node Marker */}
      <mesh position={data.position} onClick={(e) => { e.stopPropagation(); onSelect(data); }}>
        <sphereGeometry args={[0.03, 8, 8]} />
        <meshBasicMaterial color={hovered ? activeColor : regionColor} transparent opacity={opacity} />
      </mesh>

      <Text
        ref={textRef as any}
        position={data.position}
        fontSize={hovered ? 0.3 : 0.22}
        color={hovered ? activeColor : regionColor}
        anchorX="center"
        anchorY="middle"
        onClick={(e) => {
            e.stopPropagation();
            onSelect(data);
        }}
        onPointerOver={(e) => {
            e.stopPropagation();
            document.body.style.cursor = 'pointer';
            setHovered(true);
        }}
        onPointerOut={(e) => {
            document.body.style.cursor = 'default';
            setHovered(false);
        }}
        fillOpacity={opacity}
      >
        {data.text}
      </Text>
    </group>
  );
};

